select
  algorithm_uuid, algorithm_name, status, whether_to_compare, compare_group, code, abbreviation, create_time, min_mem, video_memory, algorithm_lesion, file_type, model_version, direction, nividia_amount, request_url, request_ip, image_size, timeout_seconds
from aipre_algorithm


        and algorithm_uuid = #{algorithmUuid}


        and algorithm_name = #{algorithmName}


        and status = #{status}


        and whether_to_compare = #{whetherToCompare}


        and compare_group = #{compareGroup}


        and code = #{code}


        and abbreviation = #{abbreviation}


        and create_time = #{createTime}


        and min_mem = #{minMem}


        and video_memory = #{videoMemory}


        and algorithm_lesion = #{algorithmLesion}


        and file_type = #{fileType}


        and model_version = #{modelVersion}


        and direction = #{direction}


        and nividia_amount = #{nividiaAmount}


        and request_url = #{requestUrl}


        and request_ip = #{requestIp}


        and image_size = #{imageSize}


        and timeout_seconds = #{timeoutSeconds}


limit #{pageable.offset}, #{pageable.pageSize}

select count(1)
from aipre_algorithm


        and algorithm_uuid = #{algorithmUuid}


        and algorithm_name = #{algorithmName}


        and status = #{status}


        and whether_to_compare = #{whetherToCompare}


